Create PROCEDURE [dbo].[ErrorInsert] 
		   @host [nvarchar](100) ,
		   @source [nvarchar](100),
		   @message  [nvarchar](max) ,
		   @level [nvarchar](50) ,
		   @stacktrace [nvarchar](max),
		   @variables [ntext]  

AS
BEGIN

INSERT INTO [dbo].[ErrorLog]
           ([Host]
           ,[Source]
           ,[Message]
           ,[Level]
           ,[StackTrace]
           ,[Variables])
     VALUES
           ( @host,
		   @source,
		   @message,
		   @level,
		   @stacktrace,
		   @variables )

END

Create PROCEDURE [dbo].[UserActionsHistoryInsert] 

@userName  nvarchar(50),
@controller varchar(50) = null,
@controllerAction  varchar(50) = null,
@parameters varchar(1024) = null,
@formData nvarchar(max) = null

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

INSERT INTO  [dbo].[UserActionsHistory] (
            [UserName]
           ,[Controller]
           ,[ControllerAction]
           ,[Parameters]
           ,[FormData])
     VALUES (

           @userName,
           @controller,
           @controllerAction,
           @parameters,
           @formData)
END
